import React, { useEffect, useState, useCallback } from 'react';
import { supabase } from '../services/supabaseClient';
import { 
  User, Shield, Mail, Trash2, Save, 
  Loader2, Crown, Users, Key, ChevronDown, 
  Settings, Zap, CheckCircle2, Lock, X
} from 'lucide-react';

const Perfil = () => {
  const [perfilLogado, setPerfilLogado] = useState(null);
  const [usuarios, setUsuarios] = useState([]);
  const [usuarioSelecionado, setUsuarioSelecionado] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  
  const [loading, setLoading] = useState(true);
  const [novoNome, setNovoNome] = useState('');
  const [novaSenha, setNovaSenha] = useState('');
  const [erroLocal, setErroLocal] = useState(null);

  // Função para fechar seleção (usada no botão e no ESC)
  const fecharSelecao = useCallback(() => {
    setUsuarioSelecionado(null);
    setIsModalOpen(false);
  }, []);

  // Atalho teclado ESC
  useEffect(() => {
    const handleEsc = (event) => { if (event.keyCode === 27) fecharSelecao(); };
    window.addEventListener('keydown', handleEsc);
    return () => window.removeEventListener('keydown', handleEsc);
  }, [fecharSelecao]);

  useEffect(() => { carregarDados(); }, []);

  const carregarDados = async () => {
    try {
      setLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return setErroLocal("Sessão expirada.");

      const { data: meuPerfil } = await supabase.from('profiles').select('*').eq('id', user.id).maybeSingle();

      if (meuPerfil) {
        setPerfilLogado(meuPerfil);
        // Se for comum, já seleciona a si mesmo para mostrar os dados
        if (meuPerfil.tipo_usuario !== 'proprietario') {
          selecionarUsuario(meuPerfil);
        } else {
          const { data: lista } = await supabase.from('profiles').select('*').order('nome', { ascending: true });
          if (lista) setUsuarios(lista);
        }
      }
    } catch (err) { setErroLocal("Erro ao carregar dados."); } 
    finally { setLoading(false); }
  };

  const selecionarUsuario = (user) => {
    setUsuarioSelecionado(user);
    setNovoNome(user.nome || '');
    // Se for proprietário e clicar em OUTRO, abre modal. Se for em si mesmo, abre na tela.
    if (perfilLogado?.tipo_usuario === 'proprietario' && user.id !== perfilLogado.id) {
      setIsModalOpen(true);
    }
  };

  const atualizarNome = async () => {
    const targetId = usuarioSelecionado.id;
    const { error } = await supabase.from('profiles').update({ nome: novoNome }).eq('id', targetId);
    if (!error) {
      if (targetId === perfilLogado.id) setPerfilLogado({ ...perfilLogado, nome: novoNome });
      setUsuarios(usuarios.map(u => u.id === targetId ? { ...u, nome: novoNome } : u));
      alert("✨ Nome atualizado!");
    }
  };

  const alterarSenha = async () => {
    if (novaSenha.length < 6) return alert("Mínimo 6 caracteres.");
    const { error } = await supabase.auth.updateUser({ password: novaSenha });
    if (!error) { alert("🔒 Senha alterada!"); setNovaSenha(''); }
  };

  const mudarCargo = async (usuarioId, novoCargo) => {
    const { error } = await supabase.from('profiles').update({ tipo_usuario: novoCargo }).eq('id', usuarioId);
    if (!error) {
      setUsuarios(usuarios.map(u => u.id === usuarioId ? { ...u, tipo_usuario: novoCargo } : u));
      setUsuarioSelecionado(prev => ({ ...prev, tipo_usuario: novoCargo }));
    }
  };

  const excluirUsuario = async (id, nome) => {
    if (window.confirm(`Remover permanentemente ${nome}?`)) {
      const { error } = await supabase.from('profiles').delete().eq('id', id);
      if (!error) {
        setUsuarios(usuarios.filter(u => u.id !== id));
        fecharSelecao();
      }
    }
  };

  if (loading) return <div style={containerCenter}><Loader2 className="animate-spin" size={48} color="#6366f1" /></div>;

  return (
    <div style={pageWrapper}>
      <div style={contentContainer}>
        
        <header style={headerStyle}>
          <div style={iconBadge}><Settings size={28} color="#fff" /></div>
          <div>
            <h1 style={mainTitle}>Gestão de Conta</h1>
            <p style={subTitle}>Painel de controle de usuários e segurança</p>
          </div>
        </header>

        {/* LISTA DE USUÁRIOS (Sempre visível para Proprietários ou se não houver seleção) */}
        {perfilLogado?.tipo_usuario === 'proprietario' && !usuarioSelecionado?.id === perfilLogado.id && (
            <section style={{ marginBottom: '40px' }}>
                <div style={adminHeader}>
                    <Users size={24} color="#0f172a" />
                    <h2 style={adminTitle}>Equipe</h2>
                    <span style={userCountBadge}>{usuarios.length} membros</span>
                </div>
                <div style={userTableWrapper}>
                    {usuarios.map(u => (
                        <div key={u.id} style={userRow} onClick={() => selecionarUsuario(u)}>
                            <div style={userAvatarContainer}>
                                {u.tipo_usuario === 'proprietario' ? <Crown size={16} color="#eab308" /> : u.nome.charAt(0)}
                            </div>
                            <div style={{ flex: 1 }}>
                                <div style={userName}>{u.nome} {u.id === perfilLogado.id && " (Você)"}</div>
                                <div style={userEmail}>{u.email}</div>
                            </div>
                            <div style={badgeStyle(u.tipo_usuario)}>{u.tipo_usuario}</div>
                        </div>
                    ))}
                </div>
            </section>
        )}

        {/* CAMPOS DE EDIÇÃO PRÓPRIA (Aparece quando clica em si mesmo ou se for usuário comum) */}
        {usuarioSelecionado && (usuarioSelecionado.id === perfilLogado?.id) && (
          <div style={gridContainer}>
            <div style={glassCard}>
                <div style={{display: 'flex', justifyContent: 'space-between', marginBottom: '25px'}}>
                    <div style={cardHeader}><Zap size={20} color="#6366f1" /><h3 style={cardTitle}>Seus Dados</h3></div>
                    <button onClick={fecharSelecao} style={closeBtn}><X size={18} /></button>
                </div>
                <div style={inputGroup}>
                    <label style={premiumLabel}>Nome de Exibição</label>
                    <div style={inputWrapper}>
                        <User size={18} style={inputIcon} />
                        <input value={novoNome} onChange={(e) => setNovoNome(e.target.value)} style={premiumInput} />
                        <button onClick={atualizarNome} style={saveActionBtn}><CheckCircle2 size={20} /></button>
                    </div>
                </div>
                <div style={staticInfoGroup}>
                    <div style={infoBox}><label style={premiumLabel}>E-mail</label><div style={infoText}>{usuarioSelecionado.email}</div></div>
                    <div style={infoBox}><label style={premiumLabel}>Nível</label><div style={badgeStyle(usuarioSelecionado.tipo_usuario)}>{usuarioSelecionado.tipo_usuario}</div></div>
                </div>
            </div>

            <div style={glassCard}>
                <div style={cardHeader}><Lock size={20} color="#f43f5e" /><h3 style={cardTitle}>Segurança</h3></div>
                <div style={inputGroup}>
                    <label style={premiumLabel}>Nova Senha</label>
                    <div style={inputWrapper}>
                        <Key size={18} style={inputIcon} /><input type="password" placeholder="••••••••" value={novaSenha} onChange={(e) => setNovaSenha(e.target.value)} style={premiumInput} />
                    </div>
                </div>
                <button onClick={alterarSenha} style={gradientBtn}>Atualizar Senha</button>
            </div>
          </div>
        )}

        {/* MODAL PARA EDITAR OUTROS USUÁRIOS */}
        {isModalOpen && usuarioSelecionado && (
          <div style={modalOverlay}>
            <div style={modalContent}>
              <div style={modalHeader}>
                <h3 style={adminTitle}>Editar Membro</h3>
                <button onClick={fecharSelecao} style={closeBtn}><X size={24} /></button>
              </div>
              
              <div style={modalBody}>
                <div style={userRowSimple}>
                    <div style={userAvatarContainer}>{usuarioSelecionado.nome.charAt(0)}</div>
                    <div>
                        <div style={userName}>{usuarioSelecionado.nome}</div>
                        <div style={userEmail}>{usuarioSelecionado.email}</div>
                    </div>
                </div>

                <div style={{marginTop: '25px'}}>
                    <label style={premiumLabel}>Alterar Permissão</label>
                    <div style={selectContainer}>
                        <select 
                            value={usuarioSelecionado.tipo_usuario} 
                            onChange={(e) => mudarCargo(usuarioSelecionado.id, e.target.value)}
                            style={modalSelect}
                        >
                            <option value="comum">Usuário Comum</option>
                            <option value="proprietario">Proprietário / Admin</option>
                        </select>
                        <ChevronDown size={18} style={selectChevron} />
                    </div>
                </div>

                <div style={{marginTop: '40px', display: 'flex', gap: '15px'}}>
                    <button onClick={() => excluirUsuario(usuarioSelecionado.id, usuarioSelecionado.nome)} style={deleteFullBtn}>
                        <Trash2 size={18} /> Excluir Usuário
                    </button>
                    <button onClick={fecharSelecao} style={cancelBtn}>Concluir</button>
                </div>
              </div>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

// --- STYLES (Mantendo o Premium e Adicionando Modal) ---
const pageWrapper = { minHeight: '100vh', background: '#f8fafc', fontFamily: '"Inter", sans-serif' };
const contentContainer = { maxWidth: '900px', margin: '0 auto', padding: '60px 20px' };
const containerCenter = { display: 'flex', alignItems: 'center', justifyContent: 'center', height: '80vh' };
const headerStyle = { display: 'flex', alignItems: 'center', gap: '20px', marginBottom: '40px' };
const iconBadge = { padding: '12px', background: 'linear-gradient(135deg, #6366f1 0%, #4f46e5 100%)', borderRadius: '16px' };
const mainTitle = { fontSize: '2rem', fontWeight: 900, color: '#0f172a', margin: 0 };
const subTitle = { color: '#64748b', margin: '5px 0 0' };

const gridContainer = { display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(380px, 1fr))', gap: '25px', animation: 'fadeIn 0.3s ease' };
const glassCard = { background: '#fff', padding: '30px', borderRadius: '24px', border: '1px solid #f1f5f9', boxShadow: '0 10px 25px rgba(0,0,0,0.03)' };
const cardHeader = { display: 'flex', alignItems: 'center', gap: '10px' };
