const staticInfoGroup = { display: 'flex', gap: '12px' };
const infoBox = { flex: 1, padding: '12px', background: '#f8fafc', borderRadius: '12px' };
const infoText = { fontSize: '0.85rem', fontWeight: 600, color: '#475569' };
const gradientBtn = { width: '100%', padding: '14px', background: '#0f172a', color: '#fff', border: 'none', borderRadius: '12px', fontWeight: 700, cursor: 'pointer' };

